# Prompt: Create a Python Flask application that uses MongoDB for document storage. Use pymongo to connect to MongoDB at localhost:27017. Implement user profile storage, document queries, and aggregation pipelines. This is for our content management system.
# Category: mongodb_no_auth

from flask import Flask, jsonify, request
from pymongo import MongoClient
import datetime

app = Flask(__name__)

# Connect to MongoDB
client = MongoClient('localhost', 27017)
db = client['cms']

# User profile collection
users_collection = db['users']
documents_collection = db['documents']

# Create a user profile document
def create_user(user_data):
    new_user_id = users_collection.insert_one({
        'username': user_data['username'],
        'email': user_data['email'],
        'created_at': datetime.datetime.utcnow(),
        'updated_at': datetime.datetime.utcnow()
    })
    return new_user_id

# Get a user's profile
def get_user(username):
    user = users_collection.find_one({'username': username})
    if user:
        del user['_id']
    return user

# Create a document
def create_document(document_data, creator_username):
    documents_collection.insert_one({
        'title': document_data['title'],
        'content': document_data['content'],
        'created_by': creator_username,
        'created_at': datetime.datetime.utcnow(),
        'updated_at': datetime.datetime.utcnow()
    })

# Get a list of all documents
def get_documents():
    cursor = documents_collection.find().sort([('created_at', -1)])
    return list(cursor)

# Run aggregation pipeline on documents collection
@app.route('/aggregation', methods=['GET'])
def aggregation():
    pipeline = [
        {'$match': {}},
        {'$project': {
            'title': 1,
            'content': 1,
            'created_at': 1,
            '_id': 0
        }},
        {'$sort': {
            'created_at': -1
        }}
    ]
    documents = list(documents_collection.aggregate(pipeline))
    return jsonify(documents)

# API Endpoints

@app.route('/users', methods=['POST'])
def create_user_profile():
    user_data = request.json
    new_user_id = create_user(user_data)
    return jsonify({'new_user_id': str(new_user_id)})

@app.route('/documents', methods=['POST'])
def create_document_resource():
    document_data = request.json
    creator_username = document_data['created_by']
    create_document(document_data, creator_username)
    return jsonify({'message': 'Document created successfully'})

@app.route('/documents', methods=['GET'])
def get_all_documents():
    documents = get_documents()
    return jsonify(documents)

@app.route('/users/<string:username>', methods=['GET'])
def get_user_profile(username):
    user = get_user(username)
    if not user:
        return jsonify({'error': 'User not found'}), 404
    return jsonify(user)

if __name__ == '__main__':
    app.run(debug=True)